function useInView(threshold = 0.1) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } }, { threshold });
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

function FadeIn({ children, delay = 0, style = {} }) {
  const [ref, visible] = useInView();
  return (
    <div ref={ref} style={{ opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(24px)", transition: `opacity 0.6s ease ${delay}s, transform 0.6s ease ${delay}s`, ...style }}>
      {children}
    </div>
  );
}

function Stars({ count }) {
  return <div style={{ display: "flex", gap: 2 }}>{Array.from({ length: count }, (_, i) => <span key={i} style={{ color: "#C45D2C", fontSize: "0.9rem" }}>{"\u2605"}</span>)}</div>;
}

// ========== COOKING ANIMATION ==========
function CookingLoader({ onDone }) {
  const [phase, setPhase] = useState(0);
  const messages = ["Prepping the ingredients\u2026", "Adding some spice\u2026", "Stirring with love\u2026", "Almost ready\u2026"];

  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 800);
    const t2 = setTimeout(() => setPhase(2), 3000);
    const t3 = setTimeout(() => setPhase(3), 5500);
    const t4 = setTimeout(() => onDone(), 8000);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); clearTimeout(t4); };
  }, []);

  return (
    <div style={{position:"fixed",inset:0,zIndex:9998,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",
      background:"linear-gradient(135deg,#0a2a1e,#154734 40%,#1b5e45 100%)"}}>
      <style>{`
        @keyframes stir { 0%{transform:rotate(0deg)} 100%{transform:rotate(360deg)} }
        @keyframes shake { 0%,100%{transform:rotate(0deg)} 25%{transform:rotate(15deg)} 75%{transform:rotate(-15deg)} }
        @keyframes steam { 0%{opacity:0;transform:translateY(0) scale(1)} 50%{opacity:.6} 100%{opacity:0;transform:translateY(-40px) scale(1.5)} }
        @keyframes fadeMsg { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }
        .cook-msg{animation:fadeMsg .6s ease both}
      `}</style>

      <div style={{position:"relative",width:160,height:160,marginBottom:40}}>
        {/* Pot */}
        <div style={{position:"absolute",bottom:0,left:"50%",transform:"translateX(-50%)",width:100,height:70,
          background:"linear-gradient(180deg,#3a3a3a,#222)",borderRadius:"0 0 50% 50%",border:"3px solid #555"}} />
        {/* Pot rim */}
        <div style={{position:"absolute",bottom:65,left:"50%",transform:"translateX(-50%)",width:110,height:12,
          background:"#666",borderRadius:6}} />
        {/* Spoon stirring */}
        <div style={{position:"absolute",bottom:40,left:"50%",transformOrigin:"bottom center",
          animation:"stir 2s linear infinite"}}>
          <div style={{width:6,height:80,background:"linear-gradient(180deg,#d4a574,#8b6914)",borderRadius:3,
            transform:"rotate(-20deg) translateX(-3px)"}} />
        </div>
        {/* Steam particles */}
        {[0,1,2].map(i => (
          <div key={i} style={{position:"absolute",bottom:80,left:`${40+i*20}%`,width:12+i*4,height:12+i*4,
            borderRadius:"50%",background:"rgba(255,255,255,.15)",
            animation:`steam 2s ease infinite ${i*.6}s`}} />
        ))}
        {/* Salt shaker */}
        <div style={{position:"absolute",bottom:10,right:-10,animation:"shake 1s ease infinite",transformOrigin:"bottom center"}}>
          <div style={{width:20,height:35,background:"linear-gradient(180deg,#eee,#ccc)",borderRadius:"4px 4px 2px 2px"}} />
          <div style={{width:24,height:8,background:"#999",borderRadius:"2px 2px 0 0",marginLeft:-2}} />
        </div>
      </div>

      <p className="cook-msg" key={phase} style={{fontFamily:"'Playfair Display',serif",fontSize:"1.2rem",
        fontStyle:"italic",color:"rgba(255,255,255,.7)",textAlign:"center"}}>
        {messages[Math.min(phase, messages.length - 1)]}
      </p>

      <div style={{marginTop:24,width:200,height:3,background:"rgba(255,255,255,.1)",borderRadius:2,overflow:"hidden"}}>
        <div style={{height:"100%",background:"linear-gradient(90deg,#C45D2C,#E8975B)",borderRadius:2,
          transition:"width 8s linear",width: phase >= 1 ? "100%" : "0%"}} />
      </div>
    </div>
  );
}

